// Models are discovered from data/models.json (generated by scripts/generate_models.py).
// Only directories that contain a metadata.json are included — no fallbacks for old format.

// Benchmark names whose manifests will be fetched for every model.
const BENCHMARKS = ['geobench'];

// Modes attempted for each benchmark. Missing files are silently skipped.
const BENCHMARK_MODES = ['single', 'temporal'];

const COLUMN_KEYS = {
  model: 'modelSlug',
  modelType: 'modelType',
  visionEncoder: 'visionEncoder',
  languageModel: 'languageModel',
  all: 'all',
  dataset: 'datasetName',
  emphasis: 'emphasis',
  geobench: 'geobenchVlm',
  geobenchSingle: 'geobenchSingle',
  geobenchTemporal: 'geobenchTemporal',
  params: 'modelParams'
};

const TABLE_IDS = {
  leaderboard: 'leaderboard',
  geobenchSingle: 'geobench-vlm-single',
  geobenchTemporal: 'geobench-vlm-temporal'
};

const RESULTS_INTERACTIONS_BOUND_ATTR = 'data-results-interactions-bound';

const TABLE_SORT_STATE = {};
const TABLE_SIZE_FILTER_STATE = {};
const TABLE_FILTER_STATE = {};
const TABLE_REGISTRY = new Map();
const PARAMS_TO_MILLION_CACHE = new Map();

const NON_METRIC_COLUMN_KEYS = new Set([
  COLUMN_KEYS.model,
  COLUMN_KEYS.modelType,
  COLUMN_KEYS.all,
  COLUMN_KEYS.emphasis,
  COLUMN_KEYS.dataset,
  COLUMN_KEYS.geobench,
  COLUMN_KEYS.geobenchSingle,
  COLUMN_KEYS.geobenchTemporal,
  COLUMN_KEYS.params
]);

const MODEL_SIZE_BUCKETS = [
  { key: 'all', label: 'All' },
  { key: 'lt500m', label: '< 500M', test: (m) => m < 500 },
  { key: '500m1b', label: '500M – 1B', test: (m) => m >= 500 && m < 1000 },
  { key: '1b4b', label: '1B – 4B', test: (m) => m >= 1000 && m < 4000 },
  { key: '4b10b', label: '4B – 10B', test: (m) => m >= 4000 && m < 10000 },
  { key: 'gt10b', label: '> 10B', test: (m) => m >= 10000 }
];

const MODEL_TYPE_OPTIONS = [
  { key: 'all', label: 'ALL' },
  { key: 'open-source', label: 'Open Source' },
  { key: 'api', label: 'API' }
];

document.addEventListener('DOMContentLoaded', () => {
  loadResults();
});

async function loadResults() {
  let slugs;

  try {
    slugs = await fetchJson('./data/models.json');
  } catch (err) {
    renderError('results-content', 'Could not load model index.', err);
    return;
  }

  if (!Array.isArray(slugs) || !slugs.length) {
    renderError('results-content', 'No models found.', 'data/models.json is empty or invalid.');
    return;
  }

  const modelResults = await Promise.allSettled(
    slugs.map(async (slug) => {
      // metadata.json is required — failure rejects this model entirely (no fallback)
      const metadata = await fetchJson(`./data/${slug}/metadata.json`);

      const manifestFetches = BENCHMARKS.flatMap((benchmark) =>
        BENCHMARK_MODES.map((mode) => ({
          benchmark,
          mode,
          promise: fetchJson(`./data/${slug}/${benchmark}/${mode}_manifest.json`)
        }))
      );

      const manifestResults = await Promise.allSettled(manifestFetches.map((f) => f.promise));

      return manifestResults
        .map((r, i) => ({ result: r, ...manifestFetches[i] }))
        .filter(({ result }) => result.status === 'fulfilled')
        .map(({ result, benchmark, mode }) => ({ metadata, manifest: result.value, benchmark, mode }));
    })
  );

  const entries = modelResults
    .filter((r) => r.status === 'fulfilled')
    .flatMap((r) => r.value);

  if (!entries.length) {
    const firstFailure = modelResults.find((r) => r.status === 'rejected');
    renderError('results-content', 'No benchmark results could be loaded.', firstFailure ? firstFailure.reason : 'Check that manifest files exist.');
    return;
  }

  renderManifestResults(entries);
}

async function fetchJson(path) {
  const response = await fetch(path, { cache: 'no-store' });

  if (!response.ok) {
    throw new Error(`Request failed with status ${response.status}`);
  }

  return response.json();
}

function renderManifestResults(entries) {
  const container = document.getElementById('results-content');

  const singleEntries = entries.filter((e) => e.mode === 'single');
  const temporalEntries = entries.filter((e) => e.mode === 'temporal');

  const singleRows = singleEntries.map(({ metadata, manifest }) => normalizeManifest(metadata, manifest));
  const temporalRows = temporalEntries.map(({ metadata, manifest }) => normalizeManifest(metadata, manifest));

  const sharedPrefixColumns = [
    { key: COLUMN_KEYS.model, label: 'Model' },
    { key: COLUMN_KEYS.all, label: 'Avg Score' }
  ];

  // Build leaderboard rows by grouping all entries per model slug,
  // then compute Avg Score as the mean of every available benchmark overall.
  const modelLeaderboardMap = new Map();
  entries.forEach(({ metadata, manifest, benchmark, mode }) => {
    const slug = (metadata && metadata.slug) || (manifest && manifest.model_slug) || 'unknown';
    if (!modelLeaderboardMap.has(slug)) {
      modelLeaderboardMap.set(slug, { metadata, scores: {} });
    }
    const entry = modelLeaderboardMap.get(slug);
    const overall = manifest && manifest.scores && manifest.scores.overall != null
      ? manifest.scores.overall
      : null;
    if (overall !== null) {
      entry.scores[`${benchmark}_${mode}`] = overall;
    }
  });

  const leaderboardRows = Array.from(modelLeaderboardMap.values()).map(({ metadata, scores }) => {
    const geobenchSingleScore = scores['geobench_single'];
    const geobenchTemporalScore = scores['geobench_temporal'];
    const allScores = Object.values(scores).filter((s) => Number.isFinite(Number(s)));
    const avgScore = allScores.length > 0
      ? allScores.reduce((sum, s) => sum + Number(s), 0) / allScores.length
      : null;
    return {
      [COLUMN_KEYS.model]: (metadata && metadata.name) || 'unknown',
      [COLUMN_KEYS.params]: (metadata && metadata.params) || '--',
      [COLUMN_KEYS.languageModel]: (metadata && metadata.language_model) || '--',
      [COLUMN_KEYS.visionEncoder]: (metadata && metadata.vision_encoder) || '--',
      [COLUMN_KEYS.modelType]: getMetadataModelType(metadata),
      [COLUMN_KEYS.all]: formatScore(avgScore),
      [COLUMN_KEYS.geobenchSingle]: geobenchSingleScore != null ? formatScore(geobenchSingleScore) : '--',
      [COLUMN_KEYS.geobenchTemporal]: geobenchTemporalScore != null ? formatScore(geobenchTemporalScore) : '--'
    };
  });

  const leaderboardColumns = [
    { key: COLUMN_KEYS.model, label: 'Model' },
    { key: COLUMN_KEYS.params, label: 'Param (M/B)' },
    { key: COLUMN_KEYS.languageModel, label: 'Language Model' },
    { key: COLUMN_KEYS.visionEncoder, label: 'Vision Encoder' },
    { key: COLUMN_KEYS.all, label: 'Avg Score' },
    { key: COLUMN_KEYS.geobenchSingle, label: 'GEOBench-VLM Single' },
    { key: COLUMN_KEYS.geobenchTemporal, label: 'GEOBench-VLM Temporal'}
  ];
  const geobenchNoteHtml = 'GeoBench-VLM is an Earth observation benchmark for evaluating vision-language models on satellite and aerial imagery across diverse perception and reasoning tasks. <a href="https://huggingface.co/datasets/aialliance/GEOBench-VLM" target="_blank" rel="noreferrer">Dataset</a>.';
  const leaderboardTable = {
    id: TABLE_IDS.leaderboard,
    title: 'Leaderboard',
    note: 'Comparison of vision-language models evaluated across benchmark aggregates, ranked by overall performance.',
    columns: leaderboardColumns,
    rows: leaderboardRows,
    defaultSortKey: COLUMN_KEYS.all,
    defaultSortDirection: 'desc'
  };
  const geobenchSubTables = [
    {
      id: TABLE_IDS.geobenchSingle,
      title: 'Single Image',
      columns: [...sharedPrefixColumns, ...collectMetricColumns(singleRows)],
      rows: singleRows,
      defaultSortKey: COLUMN_KEYS.all,
      defaultSortDirection: 'desc'
    },
    {
      id: TABLE_IDS.geobenchTemporal,
      title: 'Temporal',
      columns: [...sharedPrefixColumns, ...collectMetricColumns(temporalRows)],
      rows: temporalRows,
      defaultSortKey: COLUMN_KEYS.all,
      defaultSortDirection: 'desc'
    }
  ];
  const allTables = [leaderboardTable, ...geobenchSubTables];

  TABLE_REGISTRY.clear();
  allTables.forEach((table) => {
    TABLE_REGISTRY.set(table.id, table);

    if (!TABLE_SORT_STATE[table.id]) {
      TABLE_SORT_STATE[table.id] = getDefaultSortState(table);
    }

    if (!TABLE_FILTER_STATE[table.id]) {
      TABLE_FILTER_STATE[table.id] = getDefaultFilterState();
    }
  });

  container.className = 'content has-text-justified';
  container.innerHTML = `
    <div class="results-stack">
      ${renderTableCard(leaderboardTable)}
      ${renderGeobenchGroupSection(geobenchNoteHtml, geobenchSubTables)}
    </div>
  `;

  bindResultsInteractions(container);
}

function normalizeManifest(metadata, manifest) {
  const scores = manifest && manifest.scores ? manifest.scores : {};
  const perTaskScores = scores.per_task && typeof scores.per_task === 'object' ? scores.per_task : {};
  const overallScore = formatScore(scores.overall);

  // Prefer display name from metadata.json; fall back to manifest fields
  const displayName = (metadata && metadata.name)
    || (manifest && (manifest.name || manifest.model_slug))
    || 'unknown_model';

  const row = {
    [COLUMN_KEYS.model]: displayName,
    [COLUMN_KEYS.modelType]: getMetadataModelType(metadata),
    [COLUMN_KEYS.dataset]: manifest && manifest.split ? manifest.split : 'data',
    [COLUMN_KEYS.all]: overallScore,
    [COLUMN_KEYS.geobench]: overallScore,
    [COLUMN_KEYS.params]: (metadata && metadata.params) ? metadata.params : null
  };

  Object.entries(perTaskScores).forEach(([taskName, score]) => {
    row[taskName] = formatScore(score);
  });

  return row;
}

function collectMetricColumns(rows) {
  const keys = new Set();

  rows.forEach((row) => {
    Object.keys(row).forEach((key) => {
      if (!NON_METRIC_COLUMN_KEYS.has(key)) {
        keys.add(key);
      }
    });
  });

  return Array.from(keys).sort().map((key) => ({
    key,
    label: key
  }));
}

function renderTableCard(table) {
  return `
    <section class="results-section">
      <div class="results-card-header">
        <h3 class="title is-4">${escapeHtml(table.title || '')}</h3>
        ${renderTableNote(table)}
      </div>
      <article class="results-card" data-table-id="${escapeAttribute(table.id)}">
        ${renderTableCardContent(table)}
      </article>
    </section>
  `;
}

function renderGeobenchGroupSection(noteHtml, subTables) {
  return `
    <section class="results-section">
      <div class="results-card-header">
        <h3 class="title is-4">GeoBench-VLM</h3>
        <p class="results-note">${noteHtml}</p>
      </div>
      <div class="results-subsections">
        ${subTables.map((table) => `
          <section class="results-subsection">
            <h4 class="title is-5">${escapeHtml(table.title || '')}</h4>
            <article class="results-card" data-table-id="${escapeAttribute(table.id)}">
              ${renderTableCardContent(table)}
            </article>
          </section>
        `).join('')}
      </div>
    </section>
  `;
}

function renderTableCardContent(table) {
  const state = TABLE_SORT_STATE[table.id] || getDefaultSortState(table);
  const filterState = TABLE_FILTER_STATE[table.id] || getDefaultFilterState();
  const selectedBuckets = TABLE_SIZE_FILTER_STATE[table.id] || new Set();
  const filteredRows = filterRows(table.rows, selectedBuckets, filterState);
  const sortedRows = sortRows(filteredRows, state.sortKey, state.sortDirection);

  const theadHtml = table.headerGroups
    ? renderGroupedThead(table, state)
    : `<tr>${table.columns.map((column) => renderHeaderCell(column, state)).join('')}</tr>`;

  return `
    ${renderFilterToolbar(table.id)}
    <div class="benchmark-table-wrapper">
      <table class="table is-hoverable benchmark-table">
        <thead>${theadHtml}</thead>
        <tbody>
          ${sortedRows.map((row, index) => renderRow(row, table.columns, index)).join('')}
        </tbody>
      </table>
    </div>
  `;
}

function renderGroupedThead(table, state) {
  const colMap = new Map(table.columns.map((c) => [c.key, c]));

  const row1Cells = table.headerGroups.map((group) => {
    if (!group.label) {
      return group.keys.map((key) => renderHeaderCell(colMap.get(key), state, 'rowspan="2"')).join('');
    }
    return `<th colspan="${group.keys.length}" class="group-header"><span class="table-heading-label">${escapeHtml(group.label)}</span></th>`;
  }).join('');

  const row2Cells = table.headerGroups
    .filter((g) => g.label)
    .flatMap((g) => g.keys.map((key) => renderHeaderCell(colMap.get(key), state)))
    .join('');

  return `<tr>${row1Cells}</tr><tr>${row2Cells}</tr>`;
}

function paramsToMillion(params) {
  if (!params) return null;
  const normalized = String(params).trim();

  if (PARAMS_TO_MILLION_CACHE.has(normalized)) {
    return PARAMS_TO_MILLION_CACHE.get(normalized);
  }

  const match = normalized.match(/^([\d.]+)\s*([MB]?)$/i);
  if (!match) return null;

  const value = parseFloat(match[1]);
  const parsedValue = match[2].toUpperCase() === 'B' ? value * 1000 : value;

  PARAMS_TO_MILLION_CACHE.set(normalized, parsedValue);

  return parsedValue;
}

function getDefaultSortState(table) {
  return {
    sortKey: table.defaultSortKey,
    sortDirection: table.defaultSortDirection
  };
}

function getDefaultFilterState() {
  return {
    searchText: '',
    modelType: 'all'
  };
}

function filterRows(rows, selectedBuckets, filterState) {
  return filterRowsByModelType(
    filterRowsBySearch(
      filterRowsBySize(rows, selectedBuckets),
      filterState && filterState.searchText
    ),
    filterState && filterState.modelType
  );
}

function filterRowsBySize(rows, selectedBuckets) {
  if (!selectedBuckets || selectedBuckets.size === 0) return rows;
  const activeBuckets = MODEL_SIZE_BUCKETS.filter((b) => b.key !== 'all' && selectedBuckets.has(b.key));
  if (activeBuckets.length === 0) return rows;
  return rows.filter((row) => {
    const mb = paramsToMillion(row[COLUMN_KEYS.params]);
    return mb !== null && activeBuckets.some((b) => b.test(mb));
  });
}

function filterRowsBySearch(rows, searchText) {
  const normalizedSearch = String(searchText || '').trim().toLowerCase();

  if (!normalizedSearch) {
    return rows;
  }

  return rows.filter((row) => String(row[COLUMN_KEYS.model] || '').toLowerCase().includes(normalizedSearch));
}

function filterRowsByModelType(rows, modelType) {
  if (!modelType || modelType === 'all') {
    return rows;
  }

  return rows.filter((row) => row[COLUMN_KEYS.modelType] === modelType);
}

function renderFilterToolbar(tableId) {
  return `
    <div class="table-filter-toolbar">
      ${renderModelSearchControl(tableId)}
      ${renderSizeFilterControl(tableId)}
      ${renderModelTypeFilterControl(tableId)}
    </div>
  `;
}

function renderModelSearchControl(tableId) {
  const filterState = TABLE_FILTER_STATE[tableId] || getDefaultFilterState();

  return `
    <label class="table-filter-search">
      <span class="table-filter-label">Model Name</span>
      <input
        type="search"
        class="model-search-input"
        data-filter-table-id="${escapeAttribute(tableId)}"
        value="${escapeAttribute(filterState.searchText)}"
        placeholder="Search model name"
        aria-label="Search by model name">
    </label>
  `;
}

function renderSizeFilterControl(tableId) {
  return `
    <div class="table-filter-control">
      <span class="table-filter-label">Model Size</span>
      ${renderSizeFilterBar(tableId)}
    </div>
  `;
}

function renderSizeFilterBar(tableId) {
  const selectedBuckets = TABLE_SIZE_FILTER_STATE[tableId] || new Set();
  const noneSelected = selectedBuckets.size === 0;
  const buttons = MODEL_SIZE_BUCKETS.map((b) => {
    const isActive = b.key === 'all' ? noneSelected : selectedBuckets.has(b.key);
    return `
    <button type="button"
      class="size-filter-btn${isActive ? ' is-active' : ''}"
      data-size-bucket="${escapeAttribute(b.key)}"
      data-filter-table-id="${escapeAttribute(tableId)}"
      title="${b.key !== 'all' ? 'Ctrl+click to select multiple' : ''}"
      aria-pressed="${isActive}">
      ${escapeHtml(b.label)}
    </button>
  `;
  }).join('');
  return `<div class="size-filter-bar" role="group" aria-label="Filter by model size">${buttons}</div>`;
}

function renderModelTypeFilterControl(tableId) {
  return `
    <div class="table-filter-control">
      <span class="table-filter-label">Model Type</span>
      ${renderModelTypeFilterBar(tableId)}
    </div>
  `;
}

function renderModelTypeFilterBar(tableId) {
  const filterState = TABLE_FILTER_STATE[tableId] || getDefaultFilterState();
  const buttons = MODEL_TYPE_OPTIONS.map((option) => {
    const isActive = filterState.modelType === option.key;

    return `
      <button type="button"
        class="type-filter-btn${isActive ? ' is-active' : ''}"
        data-model-type="${escapeAttribute(option.key)}"
        data-filter-table-id="${escapeAttribute(tableId)}"
        aria-pressed="${isActive}">
        ${escapeHtml(option.label)}
      </button>
    `;
  }).join('');

  return `<div class="type-filter-bar" role="group" aria-label="Filter by model type">${buttons}</div>`;
}

function renderTableNote(table) {
  if (table.noteHtml) {
    return `<p class="results-note">${table.noteHtml}</p>`;
  }

  if (table.note) {
    return `<p class="results-note">${escapeHtml(table.note)}</p>`;
  }

  return '';
}

function renderHeaderCell(column, state, extraThAttr = '') {
  const label = escapeHtml(column.label || column.key || '');
  const className = column.className ? ` ${escapeAttribute(column.className)}` : '';
  const attrStr = extraThAttr ? ` ${extraThAttr}` : '';

  if (column.sortable === false) {
    return `<th class="${`static-header${className}`.trim()}"${attrStr}><span class="table-heading-label">${label}</span></th>`;
  }

  const isActive = state.sortKey === column.key;
  const direction = isActive ? state.sortDirection : '';
  const indicator = isActive ? (direction === 'desc' ? '▼' : '▲') : '▲';

  return `
    <th class="${`sortable-header${isActive ? ' is-active' : ''}${className}`.trim()}"${attrStr}>
      <button type="button" class="sort-button" data-sort-key="${escapeAttribute(column.key)}" aria-label="Sort by ${escapeAttribute(column.label || column.key || '')}">
        <span class="table-heading-label">${label}</span>
        <span class="sort-indicator" aria-hidden="true">${indicator}</span>
      </button>
    </th>
  `;
}

function renderRow(row, columns, rowIndex) {
  const classes = [];

  if (row[COLUMN_KEYS.emphasis]) {
    classes.push(`row-${escapeAttribute(row[COLUMN_KEYS.emphasis])}`);
  }

  const rowClass = classes.length ? ` class="${classes.join(' ')}"` : '';

  return `<tr${rowClass}>${columns.map((column) => renderCell(column, row, rowIndex)).join('')}</tr>`;
}

function renderCell(column, row, rowIndex) {
  const cellData = row[column.key];

  if (cellData && typeof cellData === 'object' && !Array.isArray(cellData)) {
    const tone = cellData.tone ? ` metric-${escapeAttribute(cellData.tone)}` : '';
    return `<td class="${`metric-cell${tone}`.trim()}"><div class="cell-inner">${escapeHtml(cellData.value || '')}</div></td>`;
  }

  if (column.key === COLUMN_KEYS.model) {
    return `<td class="model-name-cell"><div class="cell-inner">${escapeHtml(cellData == null ? '' : String(cellData))}</div></td>`;
  }

  if (column.key === COLUMN_KEYS.languageModel || column.key === COLUMN_KEYS.visionEncoder) {
    return `<td class="metadata-text-cell"><div class="cell-inner">${escapeHtml(cellData == null ? '' : String(cellData))}</div></td>`;
  }

  return `<td><div class="cell-inner">${escapeHtml(cellData == null ? '' : String(cellData))}</div></td>`;
}

function bindResultsInteractions(container) {
  if (container.hasAttribute(RESULTS_INTERACTIONS_BOUND_ATTR)) {
    return;
  }

  container.addEventListener('input', (event) => {
    const searchInput = event.target.closest('.model-search-input');

    if (!searchInput) {
      return;
    }

    const tableId = searchInput.getAttribute('data-filter-table-id');
    const table = TABLE_REGISTRY.get(tableId);

    if (!table || !tableId) {
      return;
    }

    const filterState = TABLE_FILTER_STATE[tableId] || getDefaultFilterState();
    filterState.searchText = searchInput.value;
    TABLE_FILTER_STATE[tableId] = filterState;

    rerenderTableCard(container, tableId, table, true);
  });

  container.addEventListener('click', (event) => {
    // Size filter button
    const filterBtn = event.target.closest('.size-filter-btn');
    if (filterBtn) {
      const tableId = filterBtn.getAttribute('data-filter-table-id');
      const bucketKey = filterBtn.getAttribute('data-size-bucket');
      const table = TABLE_REGISTRY.get(tableId);
      if (!table || !bucketKey) return;

      if (!TABLE_SIZE_FILTER_STATE[tableId]) {
        TABLE_SIZE_FILTER_STATE[tableId] = new Set();
      }
      const selected = TABLE_SIZE_FILTER_STATE[tableId];

      if (bucketKey === 'all') {
        // All: clear all selections
        selected.clear();
      } else if (event.ctrlKey || event.metaKey) {
        // Ctrl/Cmd+click: toggle this bucket in the multi-selection
        if (selected.has(bucketKey)) {
          selected.delete(bucketKey);
        } else {
          selected.add(bucketKey);
        }
      } else {
        // Normal click: select only this bucket
        selected.clear();
        selected.add(bucketKey);
      }

      rerenderTableCard(container, tableId, table, false);
      return;
    }

    const typeFilterBtn = event.target.closest('.type-filter-btn');
    if (typeFilterBtn) {
      const tableId = typeFilterBtn.getAttribute('data-filter-table-id');
      const modelType = typeFilterBtn.getAttribute('data-model-type');
      const table = TABLE_REGISTRY.get(tableId);

      if (!table || !tableId || !modelType) {
        return;
      }

      const filterState = TABLE_FILTER_STATE[tableId] || getDefaultFilterState();
      filterState.modelType = modelType;
      TABLE_FILTER_STATE[tableId] = filterState;

      rerenderTableCard(container, tableId, table, false);
      return;
    }

    // Sort button
    const button = event.target.closest('.sort-button');

    if (!button) {
      return;
    }

    const card = button.closest('[data-table-id]');

    if (!card) {
      return;
    }

    const tableId = card.getAttribute('data-table-id');
    const table = TABLE_REGISTRY.get(tableId);
    const sortKey = button.getAttribute('data-sort-key');

    if (!table || !sortKey) {
      return;
    }

    const currentState = TABLE_SORT_STATE[tableId] || getDefaultSortState(table);

    TABLE_SORT_STATE[tableId] = {
      sortKey,
      sortDirection: getNextSortDirection(sortKey, currentState)
    };

    card.innerHTML = renderTableCardContent(table);
  });

  container.setAttribute(RESULTS_INTERACTIONS_BOUND_ATTR, 'true');
}

function rerenderTableCard(container, tableId, table, restoreSearchFocus) {
  const card = container.querySelector(`[data-table-id="${CSS.escape(tableId)}"]`);

  if (!card) {
    return;
  }

  const searchText = (TABLE_FILTER_STATE[tableId] || getDefaultFilterState()).searchText;

  card.innerHTML = renderTableCardContent(table);

  if (restoreSearchFocus) {
    const searchInput = card.querySelector('.model-search-input');

    if (searchInput) {
      searchInput.focus();
      searchInput.setSelectionRange(searchText.length, searchText.length);
    }
  }
}

function getMetadataModelType(metadata) {
  const modelType = metadata && metadata.model_type;

  if (typeof modelType !== 'string') {
    return 'open-source';
  }

  return normalizeModelType(modelType);
}

function normalizeModelType(value) {
  const normalized = String(value || '').trim().toLowerCase();

  if (normalized === 'api') {
    return 'api';
  }

  return 'open-source';
}

function sortRows(rows, sortKey, sortDirection) {
  const directionFactor = sortDirection === 'asc' ? 1 : -1;

  return [...rows]
    .map((row, index) => ({ row, index }))
    .sort((left, right) => {
      const leftValue = left.row[sortKey];
      const rightValue = right.row[sortKey];

      if (sortKey === COLUMN_KEYS.model) {
        const modelComparison = compareText(leftValue, rightValue) * directionFactor;

        if (modelComparison !== 0) {
          return modelComparison;
        }

        return left.index - right.index;
      }

      const leftNumber = toNumber(leftValue);
      const rightNumber = toNumber(rightValue);
      const leftIsFinite = Number.isFinite(leftNumber);
      const rightIsFinite = Number.isFinite(rightNumber);

      if (leftIsFinite && !rightIsFinite) {
        return -1;
      }

      if (!leftIsFinite && rightIsFinite) {
        return 1;
      }

      if (leftIsFinite && rightIsFinite && leftNumber !== rightNumber) {
        return (leftNumber - rightNumber) * directionFactor;
      }

      const modelComparison = compareText(left.row[COLUMN_KEYS.model], right.row[COLUMN_KEYS.model]);

      if (modelComparison !== 0) {
        return modelComparison;
      }

      return left.index - right.index;
    })
    .map((entry) => entry.row);
}

function getNextSortDirection(sortKey, currentState) {
  if (currentState.sortKey === sortKey) {
    return currentState.sortDirection === 'desc' ? 'asc' : 'desc';
  }

  return sortKey === COLUMN_KEYS.model ? 'asc' : 'desc';
}

function compareText(leftValue, rightValue) {
  return String(leftValue || '').localeCompare(String(rightValue || ''), undefined, {
    numeric: true,
    sensitivity: 'base'
  });
}

function renderError(containerId, message, reason) {
  const container = document.getElementById(containerId);
  const detail = reason instanceof Error ? reason.message : String(reason || 'Unknown error');

  container.className = 'content has-text-justified error-panel';
  container.innerHTML = `
    <h2 class="title is-4">${escapeHtml(message)}</h2>
    <p>${escapeHtml(detail)}</p>
    <p class="error-hint">If you are previewing locally, use an HTTP server instead of opening index.html via file:// so fetch() can read the JSON files.</p>
  `;
}

function formatScore(value) {
  const numericValue = toNumber(value);

  if (!Number.isFinite(numericValue)) {
    return '--';
  }

  return numericValue.toFixed(2);
}

function toNumber(value) {
  if (typeof value === 'number') {
    return value;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : Number.NEGATIVE_INFINITY;
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function escapeAttribute(value) {
  return escapeHtml(value);
}
